require_once __DIR__.'/functions.php';if($_SERVER['REQUEST_METHOD']!=='POST'){http_response_code(405);exit;}verify_csrf();$member=require_member();$id=filter_input(INPUT_POST,'user_id',FILTER_VALIDATE_INT);$stmt=db()->prepare('SELECT profile_slug FROM users WHERE id=? AND profile_public=1 AND active=1');$stmt->execute([$id]);$slug=$stmt->fetchColumn();if(!$slug){http_response_code(404);exit('Perfil no encontrado.');}$stmt=db()->prepare('SELECT 1 FROM user_follows WHERE follower_member_id=? AND followed_user_id=?');$stmt->execute([$member['id'],$id]);if($stmt->fetchColumn()){db()->prepare('DELETE FROM user_follows WHERE follower_member_id=? AND followed_user_id=?')->execute([$member['id'],$id]);}else{db()->prepare('INSERT INTO user_follows(follower_member_id,followed_user_id) VALUES(?,?)')->execute([$member['id'],$id]);}redirect('/autor/'.rawurlencode((string)$slug));
